patch:
diff --git a/llvm/lib/Target/SystemZ/SystemZTargetTransformInfo.cpp b/llvm/lib/Target/SystemZ/SystemZTargetTransformInfo.cpp
index e44777c5c485..f9731f9627f6 100644
--- a/llvm/lib/Target/SystemZ/SystemZTargetTransformInfo.cpp
+++ b/llvm/lib/Target/SystemZ/SystemZTargetTransformInfo.cpp
@@ -779,6 +779,24 @@ InstructionCost SystemZTTIImpl::getCastInstrCost(unsigned Opcode, Type *Dst,
   unsigned DstScalarBits = Dst->getScalarSizeInBits();
   unsigned SrcScalarBits = Src->getScalarSizeInBits();

+  // Handle scalar-to-vector casts, which can occur during SLP vectorization.
+  if (!Src->isVectorTy() && Dst->isVectorTy()) {
+    // For scalar-to-vector casts, we estimate the cost as the scalar cast cost
+    // plus the cost of replicating the result across the vector elements.
+    if (ST->hasVector()) {
+      Type *DstEltTy = Dst->getScalarType();
+      InstructionCost ScalarCost = getCastInstrCost(Opcode, DstEltTy, Src, CCH, CostKind, I);
+      if (!ScalarCost.isValid())
+        return ScalarCost;
+      
+      // Add replication cost: one instruction per vector register.
+      unsigned NumVecRegs = getNumVectorRegs(Dst);
+      return ScalarCost + NumVecRegs;
+    }
+    // Fall back to base implementation if no vector support.
+    return BaseT::getCastInstrCost(Opcode, Dst, Src, CCH, CostKind, I);
+  }
+
   if (!Src->isVectorTy()) {
     assert (!Dst->isVectorTy());

